SELECT (YEAR(?date) AS ?year) (SUM(IF(?country = wd:Q30, 1, 0)) * 100.0 / COUNT(?person) AS ?percentage) WHERE {
  ?person wdt:P27 ?country.
  ?person p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?awardInstance;
               pq:P585 ?date.
  ?awardInstance wdt:P31 wd:Q1784.
  FILTER(YEAR(?date) >= 1924 && YEAR(?date) <= 2023)
} GROUP BY ?year ORDER BY ?year

